import { Link } from "react-router-dom";

function MenuVertical() {
    return (
        <ul className="menu-vertical">
            <li className="item-vertical"><Link to="Productos#combos">COMBOS</Link></li>
            <li className="item-vertical"><Link to="Productos#burguers">BURGUERS</Link></li>
            <li className="item-vertical"><Link to="Productos#bebidas">BEBIDAS</Link></li>
        </ul>
    );
};

export default MenuVertical;
